import type { Meta, StoryObj } from '@storybook/react-vite';
import { Statistic } from './Statistic';
import { Space } from '../Space';

const meta = {
  title: 'Components/Statistic',
  component: Statistic,
  tags: ['autodocs'],
  argTypes: {
    value: { control: 'text' },
    title: { control: 'text' },
    prefix: { control: 'text' },
    suffix: { control: 'text' },
    precision: { control: 'number' },
    groupSeparator: { control: 'text' },
    decimalSeparator: { control: 'text' },
    valueStyle: { control: false },
    formatter: { control: false },
  },
  args: {
    title: 'Active users',
    value: 268500,
  },
} satisfies Meta<typeof Statistic>;

export default meta;
type Story = StoryObj<typeof meta>;

export const Playground: Story = {
  render: (args) => <Statistic {...args} />,
};

export const Group: Story = {
  name: 'A row of statistics',
  render: () => (
    <Space wrap style={{ gap: 48 }}>
      <Statistic title="Active users" value={268500} />
      <Statistic title="Account balance" value={1128.42} precision={2} prefix="$" />
      <Statistic title="Conversion rate" value={68.4} precision={1} suffix="%" />
    </Space>
  ),
};

export const Precision: Story = {
  name: 'Precision and separators',
  render: () => (
    <Space wrap style={{ gap: 48 }}>
      <Statistic title="Revenue" value={1234567.891} precision={2} prefix="$" />
      <Statistic
        title="European format"
        value={1234567.89}
        precision={2}
        groupSeparator="."
        decimalSeparator=","
        suffix="€"
      />
    </Space>
  ),
};

export const ColoredValue: Story = {
  name: 'Colored value',
  render: () => (
    <Space wrap style={{ gap: 48 }}>
      <Statistic
        title="Net profit"
        value={32.18}
        precision={2}
        prefix="+"
        suffix="%"
        valueStyle={{ color: 'var(--ec-color-success)' }}
      />
      <Statistic
        title="Churn"
        value={-4.7}
        precision={1}
        suffix="%"
        valueStyle={{ color: 'var(--ec-color-danger)' }}
      />
    </Space>
  ),
};

import {
  type CSSProperties,
  forwardRef,
  type HTMLAttributes,
  type ReactNode,
} from 'react';
import { cls, useNamespace } from '../../utils';

export interface StatisticProps
  extends Omit<HTMLAttributes<HTMLDivElement>, 'prefix' | 'title'> {
  /** The value to display. Numeric values are formatted; strings are shown as-is. */
  value: number | string;
  /** Title shown above the value. */
  title?: ReactNode;
  /** Content rendered before the value. */
  prefix?: ReactNode;
  /** Content rendered after the value. */
  suffix?: ReactNode;
  /** Number of decimal places to keep (numeric values only). */
  precision?: number;
  /** Thousands group separator. */
  groupSeparator?: string;
  /** Decimal separator. */
  decimalSeparator?: string;
  /** Inline style applied to the value element. */
  valueStyle?: CSSProperties;
  /** Custom formatter. When provided it overrides the built-in number formatting. */
  formatter?: (value: number | string) => ReactNode;
  children?: ReactNode;
}

/**
 * Format a numeric value applying precision and group/decimal separators.
 * Strings are returned untouched so callers can pass pre-formatted content.
 */
function formatNumber(
  value: number | string,
  precision: number | undefined,
  groupSeparator: string,
  decimalSeparator: string,
): string {
  if (typeof value !== 'number' || !Number.isFinite(value)) {
    return String(value);
  }

  const fixed = precision !== undefined ? value.toFixed(precision) : String(value);
  const negative = fixed.startsWith('-');
  const unsigned = negative ? fixed.slice(1) : fixed;
  const [intPart, decimalPart] = unsigned.split('.');

  const groupedInt = intPart.replace(/\B(?=(\d{3})+(?!\d))/g, groupSeparator);
  const body = decimalPart !== undefined ? `${groupedInt}${decimalSeparator}${decimalPart}` : groupedInt;

  return negative ? `-${body}` : body;
}

export const Statistic = forwardRef<HTMLDivElement, StatisticProps>(function Statistic(props, ref) {
  const {
    value,
    title,
    prefix,
    suffix,
    precision,
    groupSeparator = ',',
    decimalSeparator = '.',
    valueStyle,
    formatter,
    className,
    children,
    ...rest
  } = props;

  const ns = useNamespace('statistic');

  const displayValue: ReactNode = formatter
    ? formatter(value)
    : formatNumber(value, precision, groupSeparator, decimalSeparator);

  return (
    <div ref={ref} className={cls(ns.b(), className)} {...rest}>
      {(title !== undefined && title !== null) && <div className={ns.e('head')}>{title}</div>}
      <div className={ns.e('content')}>
        {(prefix !== undefined && prefix !== null) && (
          <span className={ns.e('prefix')}>{prefix}</span>
        )}
        <span className={ns.e('number')} style={valueStyle}>
          {displayValue}
        </span>
        {(suffix !== undefined && suffix !== null) && (
          <span className={ns.e('suffix')}>{suffix}</span>
        )}
      </div>
      {children}
    </div>
  );
});

.ec-statistic {
  --ec-statistic-title-font-size: var(--ec-font-size-base);
  --ec-statistic-title-color: var(--ec-text-color-regular);
  --ec-statistic-content-font-size: 24px;
  --ec-statistic-content-color: var(--ec-text-color-primary);

  box-sizing: border-box;
  font-family: inherit;
}

.ec-statistic__head {
  margin-bottom: 4px;
  font-size: var(--ec-statistic-title-font-size);
  font-weight: var(--ec-font-weight-primary);
  line-height: 20px;
  color: var(--ec-statistic-title-color);
}

.ec-statistic__content {
  display: inline-flex;
  align-items: center;
  font-size: var(--ec-statistic-content-font-size);
  color: var(--ec-statistic-content-color);
}

.ec-statistic__prefix {
  display: inline-flex;
  align-items: center;
  margin-right: 4px;
}

.ec-statistic__suffix {
  display: inline-flex;
  align-items: center;
  margin-left: 4px;
}

.ec-statistic__number {
  font-weight: var(--ec-font-weight-primary);
}
